INSERT INTO `Product` (`id`,`name`,`slug`,`category`,`price`,`img`,`alt`,`shortDescription`,`description`,`salePrice`,`stock`,`createdAt`,`updatedAt`) VALUES ('cmo53bptp0006o1wmk8mia8d4','Racor de cobre diámetro 4mm PC4 - M6','racor-de-cobre-diametro-4mm-pc4-m6','Repuestos para impresoras 3D',10000,'https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961351/conectores-neumaticos-pc4-m6-impresora-3d_sv5nym.png','Racor de cobre diámetro 4mm PC4 - M6',NULL,'Este es el número de modelo del racor, identificando específicamente su diseño y tamaño para una fácil referencia y compatibilidad con otros componentes de la impresora 3D.\r\\n\r\\nDiseñado para su uso con tubos de PTFE de diámetro exterior de 4 mm, lo que los hace compatibles con una variedad de impresoras 3D que utilizan este tipo de tubo para guiar el filamento desde el extrusor hasta el hotend.\r\\n\r\\nSe adapta a tubos de PTFE utilizados para filamentos de 1.75 mm y 3 mm de diámetro, lo que proporciona versatilidad en su aplicación y compatibilidad con diferentes tamaños de filamento.',NULL,97,'2026-04-19 01:31:42','2026-04-19 01:31:42');
