INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmognsld40002o1ukc1bl89ub','Rejilla de Ventilación Personalizada para Carros','repotenciacion','En CESGAR utilizamos la impresión 3D para ofrecer soluciones a medida, como la fabricación de repuestos automotrices descontinuados. En este caso de éxito, diseñamos y fabricamos una rejilla de ventilación personalizada para un vehículo de los años 90, logrando una pieza rentable que recaptura la estética y funcionalidad originales, manteniendo vivas las joyas automovilísticas clásicas.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961459/rejilla-ventilacion-personalizada-carros_ht5coq.png','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":"left","level":2},"content":[{"type":"text","text":"Rejilla de Ventilación Personalizada para Carros"}]},{"type":"paragraph","attrs":{"textAlign":"left"},"content":[{"type":"text","text":"En CESGAR, nos especializamos en soluciones personalizadas para desafíos únicos. Un ejemplo reciente es nuestro trabajo con un cliente que posee un carro de los 90′. Este cliente no lograba encontrar el repuesto de la rejilla de ventilación que se había roto con el tiempo."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/rejilla-ventilacion-personalizada-carros.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":"left"},"content":[{"type":"text","text":"Haciendo uso de la impresión 3D, hemos diseñado y fabricado una rejilla de ventilación que no solo se adapta perfectamente al vehículo, sino que también recaptura la estética y funcionalidad del diseño original, satisfaciendo plenamente las necesidades del cliente de manera rentable."}]},{"type":"heading","attrs":{"textAlign":"left","level":3},"content":[{"type":"text","text":"Rejilla de Ventilación Original: Testimonio de Tiempo y Uso"}]},{"type":"paragraph","attrs":{"textAlign":"left"},"content":[{"type":"text","text":"En CESGAR, exploramos las posibilidades de la impresión 3D para ayudar a nuestros clientes a superar sus desafíos y mantener vivas las joyas automovilísticas del pasado."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/imagen_2023-10-31_134703695.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":"left"},"content":[{"type":"text","text":"Este es solo un ejemplo de cómo nuestros servicios de impresión 3D pueden ayudar a nuestros clientes a personalizar sus productos y a llevar sus ideas a la realidad."}]}]}','published','2026-04-29 00:45:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 03:50:10','2026-04-27 04:33:10');
INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmogoyawe000lo1uk0g65bwka','Repotenciación de impresora 3D Ender 3','repotenciacion-de-impresora-3d-ender-3','En este artículo detallamos la completa repotenciación de una impresora 3D Ender 3 llevada a cabo por CESGAR para superar sus limitaciones de fábrica. Mediante la conversión a un sistema mecánico CoreXZ con guías lineales y la integración de electrónica avanzada con Klipper y Raspberry Pi, logramos aumentar drásticamente la velocidad de impresión hasta 200 mm/s mejorando la precisión y el control; un servicio de actualización integral que ahora ofrecemos a todos los entusiastas de la fabricación digital.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961471/optimizacion-ender-3-voron_stdudw.webp','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Repotenciación de impresora 3D Ender 3"}]},{"type":"paragraph","attrs":{"textAlign":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"La Ender 3 es una de las impresoras 3D más populares del mercado gracias a su bajo costo y buen rendimiento. De fábrica, ofrece una estructura cartesiana básica, volumen de impresión de 220x220x250 mm, velocidades de impresión moderadas (alrededor de "},{"type":"text","marks":[{"type":"bold"}],"text":"60 mm/s"},{"type":"text","text":") y un extrusor tipo Bowden que cumple con tareas generales, pero presenta limitaciones para proyectos más exigentes."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2025/05/impresora-3d-ender-3impresora-3d-ender-3-600x600.webp","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Con el objetivo de superar estas limitaciones, realizamos una completa repotenciación de la máquina. Imprimimos todas las piezas necesarias para su transformación y reemplazamos los rodamientos por guías lineales, aumentando la precisión y reduciendo la fricción. Mecánicamente, rediseñamos la estructura para convertirla en un sistema CoreXZ, lo que nos permitió alcanzar velocidades de hasta "},{"type":"text","marks":[{"type":"bold"}],"text":"200 mm/s"},{"type":"text","text":" sin comprometer la calidad de impresión."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2025/05/ender-3-voron-600x800.webp","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En el apartado electrónico, complementamos a la placa original una Raspberry Pi, una expansión para Klipper, un acelerómetro para calibraciones más finas, e instalamos luces LED para mejorar la visibilidad del área de trabajo. Además, actualizamos el extrusor para lograr una mejor alimentación del filamento."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2025/05/optimizacion-ender-3-voron-600x450.webp","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"La implementación de Klipper como firmware nos brindó un control más preciso de los movimientos y tiempos, optimizando así el rendimiento general de la máquina."}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Invitamos a todos los usuarios de impresoras 3D a repotenciar sus equipos con CESGAR, donde ofrecemos tanto el servicio de modificación como la venta de repuestos y accesorios. ¡Dale nueva vida a tu impresora y alcanza un nuevo nivel de calidad y velocidad!"}]}]}','published','2026-04-27 09:21:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 04:22:36','2026-04-27 04:24:23');
INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmogp6bnn0013o1ukli53dwhy','Escáner 3D en la modificación de moldes','escaner-3d-en-la-modificacion-de-moldes','Descubre cómo en CESGAR aplicamos el escaneo y modelado 3D para ofrecer servicios de ingeniería inversa. En este artículo, mostramos un caso de éxito donde ayudamos a un cliente del sector de inyección de plástico a digitalizar y modificar su molde original, optimizando sus procesos de producción sin necesidad de recursos internos adicionales.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961471/escaneo-3d-de-un-molde-industrial-para-digitalizacion-y-control-de-calidad_xnxm76.png','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Escáner 3D en la modificación de moldes"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, ofrecemos una gama de servicios de impresión 3D que van más allá de la simple producción de piezas. Uno de estos servicios es la ingeniería inversa, que permite a nuestros clientes personalizar sus moldes y mejorar su proceso de producción."}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Un ejemplo de esto es nuestro trabajo con un cliente que desarrolla piezas mediante inyección de plástico. Este cliente necesitaba personalizar su molde, pero no tenía la capacidad de hacerlo internamente."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/escaneo-3d-de-un-molde-industrial-para-digitalizacion-y-control-de-calidad.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, utilizamos nuestro servicio de escaneo y modelado 3D para realizar ingeniería inversa del molde. Esto permitió a nuestro cliente visualizar el molde en un formato digital y hacer las modificaciones necesarias."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/escaneo-3d-moldes-industriales.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Este servicio de ingeniería inversa es solo uno de los muchos que CESGAR ofrece para ayudar a nuestros clientes a optimizar sus procesos de producción y a aprovechar al máximo la tecnología de impresión 3D."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/imagen_2023-10-23_120111926.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Este es solo un ejemplo de cómo nuestros servicios de impresión 3D pueden ayudar a nuestros clientes a personalizar sus productos y a llevar sus ideas a la realidad."}]}]}','published','2026-04-27 04:27:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 04:28:50','2026-04-27 04:28:50');
INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmogphw0i001ko1uktvm19h5s','HMI personalizado','hmi-personalizado','En este artículo mostramos cómo en CESGAR transformamos un diseño digital en una solución física y funcional. Presentamos el caso de un cliente que diseñó una carcasa (case) a medida para un dispositivo HMI y nos envió el archivo STL. Gracias a nuestros servicios de impresión 3D bajo demanda, logramos fabricar una pieza de protección exacta y adaptada a sus necesidades específicas, demostrando las ventajas de la manufactura personalizada frente a las opciones estándar del mercado.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961476/impresion-3d-hmi-personalizado_gmmpfi.png','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"HMI Personalizado: Del Diseño a la Realidad"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, nos enorgullece ofrecer servicios de impresión 3D que permiten a nuestros clientes llevar sus ideas del diseño digital al mundo físico. Un ejemplo destacado de esto es nuestro reciente trabajo con un cliente que diseñó un "},{"type":"text","marks":[{"type":"italic"}],"text":"case"},{"type":"text","text":" (carcasa) personalizado para un HMI (Interfaz Hombre-Máquina). A menudo, estos dispositivos requieren protecciones robustas o montajes muy específicos para su entorno de trabajo, algo que las soluciones comerciales estándar rara vez logran cubrir a la perfección."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/impresion-3d-hmi-personalizado.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Este cliente tenía necesidades muy particulares de montaje y ergonomía para su proyecto, por lo que diseñó una carcasa que se ajustaba milimétricamente a su maquinaria. Una vez finalizado, nos envió su diseño en formato STL, que es el tipo de archivo estándar más utilizado en la impresión 3D. Al recibir el modelo, nuestro equipo pudo procesarlo rápidamente para prepararlo para la fabricación."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/impresion-3d-de-un-panel-de-interfaz-hombre-maquina-hmi-personalizado.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, utilizamos nuestras impresoras 3D para producir el "},{"type":"text","marks":[{"type":"italic"}],"text":"case"},{"type":"text","text":" exactamente según el diseño del cliente, utilizando materiales capaces de proteger adecuadamente los componentes electrónicos internos. Este servicio de manufactura bajo demanda permite a nuestros clientes tener un control total sobre el diseño y la funcionalidad de sus productos, asegurando que se integren perfectamente a sus necesidades sin los altos costos de la inyección de plástico tradicional."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/imagen_2023-10-23_112137199.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Este caso de éxito es solo un ejemplo de cómo nuestros servicios de impresión 3D pueden ayudar a nuestros clientes a personalizar sus equipos, superar barreras de hardware y llevar sus ideas directamente a la realidad."}]}]}','published','2026-04-27 04:36:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 04:37:50','2026-04-27 04:37:50');
INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmogpmxhv001to1ukl8m1wcd2','Bandeja de goteo para máquinas vending','bandeja-de-goteo-para-maquinas-vending','En este caso de éxito, explicamos cómo CESGAR solucionó el problema de escasez de repuestos para un cliente del sector de máquinas vending. Al diseñar y fabricar bandejas de goteo mediante impresión 3D, logramos sustituir las costosas y lentas importaciones por una producción local bajo demanda. Esto no solo redujo los tiempos de inactividad de las máquinas, sino que generó ahorros significativos, demostrando la rentabilidad de la manufactura aditiva en el mantenimiento de equipos.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961439/bandeja-de-goteo-para-maquinas-vending-recogiendo-liquidos-derramados_gbhk7z.png','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Bandeja de Goteo para Máquinas Vending: Soluciones Bajo Demanda"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, utilizamos la impresión 3D para ofrecer soluciones personalizadas a problemas industriales y comerciales de todo tipo. Un excelente ejemplo de esto es nuestro reciente trabajo con un cliente del sector de dispensadores automáticos, quien necesitaba reemplazar las bandejas de goteo dañadas o extraviadas en sus máquinas "},{"type":"text","marks":[{"type":"italic"}],"text":"vending"},{"type":"text","text":". A menudo, conseguir estos repuestos específicos implica lidiar con piezas descontinuadas, altos costos de envío o largos tiempos de espera por importación."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/bandeja-goteo-maquinas-vending.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Para resolver este inconveniente, desarrollamos un modelo digital exacto y fabricamos un prototipo de repuesto utilizando impresión 3D con materiales resistentes. Esta alternativa eliminó por completo la necesidad de importar las piezas, permitiendo una producción local y bajo demanda. De esta forma, el cliente puede solicitar exactamente la cantidad de bandejas que necesita, en el momento que las necesita, lo que se traduce en una reducción del tiempo de inactividad de sus máquinas y en ahorros económicos significativos."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/10/bandeja-de-goteo-para-maquinas-vending-recogiendo-liquidos-derramados.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, demostramos día a día cómo la manufactura aditiva y la impresión 3D son herramientas clave para ofrecer soluciones ágiles, personalizadas y altamente rentables, optimizando el mantenimiento de equipos para nuestros clientes."}]},{"type":"paragraph","attrs":{"textAlign":null}}]}','published','2026-04-27 09:40:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 04:41:45','2026-04-27 04:42:34');
INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmogpsdfv002ao1ukrh26331f','Bomba Dosificadora para Producción de Bioetanol','bomba-dosificadora-para-produccion-de-bioetanol','En este artículo destacamos el desarrollo de una bomba dosificadora para la producción de bioetanol. Mediante el uso de impresión 3D, en CESGAR diseñamos y fabricamos una bomba peristáltica impulsada por un motor paso a paso. Esta solución a medida no solo redujo drásticamente los costos frente a las alternativas comerciales, sino que proporcionó la precisión y la resistencia necesarias para el manejo de fluidos industriales, demostrando el potencial de la manufactura aditiva en el sector energético.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961395/bomba-dosificadora-de-precision-para-uso-en-la-produccion-de-bioetanol-600x487_qh6zjd.jpg','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Bomba Dosificadora para Producción de Bioetanol"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, nos especializamos en diseñar soluciones personalizadas para desafíos industriales únicos. Un excelente ejemplo de nuestra capacidad de innovación es nuestro trabajo con un cliente del sector energético que necesitaba una bomba dosificadora precisa para su línea de producción de bioetanol. A menudo, los equipos comerciales que ofrecen este nivel de precisión tienen costos prohibitivos o no se adaptan fácilmente a sistemas experimentales o a medida."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/07/bomba-dosificadora-de-precision-para-uso-en-la-produccion-de-bioetanol.jpg","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Para dar respuesta a esta necesidad, utilizamos el modelado y la impresión 3D para desarrollar una bomba peristáltica completamente funcional, impulsada por un motor paso a paso. Este diseño es ideal para el manejo de químicos y bioetanol, ya que el fluido solo tiene contacto con la manguera interna, evitando la corrosión de las piezas mecánicas y garantizando un bombeo exacto, controlado y libre de contaminación."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/07/bomba-dosificadora-produccion-bioetanol.jpg","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Gracias a la manufactura aditiva, logramos fabricar el rotor y la carcasa cumpliendo con las especificaciones técnicas del cliente de una manera altamente rentable y eficiente. En CESGAR, seguimos explorando y ampliando las posibilidades de la impresión 3D para ayudar a la industria a superar sus desafíos tecnológicos con soluciones accesibles."}]}]}','published','2026-04-27 04:44:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 04:45:59','2026-04-27 04:45:59');
INSERT INTO `BlogPost` (`id`,`title`,`slug`,`excerpt`,`coverImage`,`content`,`status`,`publishedAt`,`authorId`,`createdAt`,`updatedAt`) VALUES ('cmogpyey3002ko1ukodg2pqtu','Soporte de Motor Batidor: Producción Bajo Demanda y Mayor Resistencia','soporte-de-motor-batidor-produccion-bajo-demanda-y-mayor-resistencia','En este caso de éxito, abordamos el problema de un cliente de máquinas vending que sufría por la fragilidad del soporte de su motor batidor y las costosas importaciones para reemplazarlo. En CESGAR, rediseñamos y fabricamos mediante impresión 3D un repuesto más resistente y producido localmente. Esta solución permite la fabricación bajo demanda, eliminando la necesidad de importar grandes lotes y optimizando los costos de mantenimiento del cliente.','https://res.cloudinary.com/dpnv9gx8m/image/upload/v1778961464/soporte-motor-batidor_fg59v9.png','{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Soporte de Motor Batidor: Producción Bajo Demanda y Mayor Resistencia"}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/07/soporte-o-carcasa-de-montaje-para-un-motor-de-batidor.jpg","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, nos enorgullece ofrecer servicios de impresión 3D para tirajes cortos y producción bajo demanda, proporcionando eficiencia, agilidad y flexibilidad a nuestros clientes industriales y comerciales."}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Un claro ejemplo de cómo la manufactura aditiva puede resolver problemas logísticos y de diseño es nuestro trabajo con un cliente que opera máquinas "},{"type":"text","marks":[{"type":"italic"}],"text":"vending"},{"type":"text","text":". Ellos se enfrentaban a un inconveniente recurrente con un repuesto específico: el soporte del motor batidor. La pieza de fábrica era frágil, propensa a romperse con el uso continuo, y su reemplazo requería largas y costosas importaciones obligando a comprar en grandes cantidades."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/07/soporte-motor-batidor.jpg","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Para solucionar este cuello de botella, utilizamos la impresión 3D para rediseñar y desarrollar un repuesto estructuralmente más resistente. Al fabricarlo localmente con materiales duraderos, eliminamos por completo la necesidad de importación. Además, este proceso productivo es altamente escalable y permite trabajar estrictamente bajo demanda; esto significa que el cliente ahora solo solicita la cantidad exacta que necesita, en el momento que la necesita, sin que el costo unitario por pieza se vea afectado."}]},{"type":"image","attrs":{"src":"https://cesgar.com.co/wp-content/uploads/2023/07/soporte-motor-batidor.png","alt":null,"title":null,"width":null,"height":null}},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"En CESGAR, estamos emocionados por las infinitas posibilidades que la impresión 3D ofrece para la optimización del mantenimiento de equipos, y estamos fuertemente comprometidos a ayudar a nuestros clientes a aprovechar todos estos beneficios técnicos y económicos."}]}]}','published','2026-04-27 14:48:00','cmnz7mf66000ro1bb0rqw34av','2026-04-27 04:50:41','2026-04-27 16:37:46');
